### New File: `src/services/orderService.ts`

```typescript
import { orders, products, getNextOrderId } from "../data.js";
import { ServiceError } from "../errors.js";
import type {
  CreateOrderInput,
  OrderItem,
  Order,
  OrderFilters,
  OrderListResult,
  EnrichedOrder,
} from "../types.js";

export function listOrders(filters: OrderFilters): OrderListResult {
  let filtered = [...orders];

  if (filters.userId !== undefined) {
    filtered = filtered.filter((o) => o.userId === filters.userId);
  }

  if (filters.status !== undefined) {
    filtered = filtered.filter((o) => o.status === filters.status);
  }

  const totalRevenue = filtered.reduce((sum, o) => sum + o.total, 0);

  return {
    orders: filtered,
    summary: {
      count: filtered.length,
      totalRevenue: Math.round(totalRevenue * 100) / 100,
    },
  };
}

export function getOrder(id: number): EnrichedOrder {
  const order = orders.find((o) => o.id === id);
  if (!order) {
    throw new ServiceError(404, "Order not found");
  }

  const enrichedItems = order.items.map((item) => {
    const product = products.find((p) => p.id === item.productId);
    return {
      ...item,
      productName: product?.name ?? "Unknown",
    };
  });

  return {
    ...order,
    items: enrichedItems,
  };
}

export function createOrder(input: CreateOrderInput): Order {
  if (!input.userId || !input.items || !Array.isArray(input.items)) {
    throw new ServiceError(400, "userId and items are required");
  }

  if (input.items.length === 0) {
    throw new ServiceError(400, "Order must have at least one item");
  }

  const orderItems: OrderItem[] = [];
  let total = 0;

  for (const item of input.items) {
    const product = products.find((p) => p.id === item.productId);
    if (!product) {
      throw new ServiceError(400, `Product ${item.productId} not found`);
    }

    if (item.quantity <= 0) {
      throw new ServiceError(400, "Quantity must be positive");
    }

    if (product.stock < item.quantity) {
      throw new ServiceError(
        400,
        `Insufficient stock for ${product.name}`
      );
    }

    product.stock -= item.quantity;

    const itemTotal = product.price * item.quantity;
    orderItems.push({
      productId: product.id,
      quantity: item.quantity,
      price: product.price,
    });
    total += itemTotal;
  }

  const order: Order = {
    id: getNextOrderId(),
    userId: input.userId,
    items: orderItems,
    total: Math.round(total * 100) / 100,
    status: "pending",
    createdAt: new Date().toISOString(),
  };

  orders.push(order);

  return order;
}

export function updateOrderStatus(
  id: number,
  status: string
): Order {
  const order = orders.find((o) => o.id === id);
  if (!order) {
    throw new ServiceError(404, "Order not found");
  }

  const validStatuses = ["pending", "confirmed", "shipped", "delivered"];
  if (!validStatuses.includes(status)) {
    throw new ServiceError(
      400,
      `Invalid status. Must be one of: ${validStatuses.join(", ")}`
    );
  }

  const transitions: Record<string, string[]> = {
    pending: ["confirmed"],
    confirmed: ["shipped"],
    shipped: ["delivered"],
    delivered: [],
  };

  if (!transitions[order.status]?.includes(status)) {
    throw new ServiceError(
      400,
      `Cannot transition from ${order.status} to ${status}`
    );
  }

  order.status = status as typeof order.status;

  return order;
}
```

Key observations:
- `createOrder` accepts a `CreateOrderInput`, performs all validation and stock mutations, and returns the created `Order`. This is the most complex function and it preserves the exact sequential validation behavior from the current handler (validating each item in order, deducting stock as it goes).
- `updateOrderStatus` encapsulates the state machine logic. The valid transitions map is pure business logic that belongs here.
- Error messages are preserved character-for-character so the HTTP-level tests that check error responses continue to pass.

