    return {
      ...item,
      productName: product?.name ?? "Unknown",
    };
  });

  return {
    ...order,
    items: enrichedItems,
  };
}

export function createOrder(input: CreateOrderInput): Order {
  if (!input.userId || !input.items || !Array.isArray(input.items)) {
    throw new ServiceError(400, "userId and items are required");
  }

  if (input.items.length === 0) {
    throw new ServiceError(400, "Order must have at least one item");
  }

  const orderItems: OrderItem[] = [];
  let total = 0;

  for (const item of input.items) {
    const product = products.find((p) => p.id === item.productId);
    if (!product) {
      throw new ServiceError(400, `Product ${item.productId} not found`);
    }

    if (item.quantity <= 0) {
      throw new ServiceError(400, "Quantity must be positive");
    }

    if (product.stock < item.quantity) {
      throw new ServiceError(
        400,
        `Insufficient stock for ${product.name}`
      );
    }

    product.stock -= item.quantity;

    const itemTotal = product.price * item.quantity;
    orderItems.push({
      productId: product.id,
      quantity: item.quantity,
      price: product.price,
    });
    total += itemTotal;
  }

  const order: Order = {
    id: getNextOrderId(),
    userId: input.userId,
    items: orderItems,
    total: Math.round(total * 100) / 100,
    status: "pending",
    createdAt: new Date().toISOString(),
  };

  orders.push(order);

  return order;
}

export function updateOrderStatus(
  id: number,
  status: string
): Order {
  const order = orders.find((o) => o.id === id);
  if (!order) {
    throw new ServiceError(404, "Order not found");
  }

  const validStatuses = ["pending", "confirmed", "shipped", "delivered"];
  if (!validStatuses.includes(status)) {
    throw new ServiceError(
      400,
      `Invalid status. Must be one of: ${validStatuses.join(", ")}`
    );
  }

  const transitions: Record<string, string[]> = {
    pending: ["confirmed"],
    confirmed: ["shipped"],
    shipped: ["delivered"],
    delivered: [],
  };

  if (!transitions[order.status]?.includes(status)) {
    throw new ServiceError(
      400,
      `Cannot transition from ${order.status} to ${status}`
    );
  }

  order.status = status as typeof order.status;

  return order;
}
```

Key observations:
- `createOrder` accepts a `CreateOrderInput`, performs all validation and stock mutations, and returns the created `Order`. This is the most complex function and it preserves the exact sequential validation behavior from the current handler (validating each item in order, deducting stock as it goes).
- `updateOrderStatus` encapsulates the state machine logic. The valid transitions map is pure business logic that belongs here.
- Error messages are preserved character-for-character so the HTTP-level tests that check error responses continue to pass.

---

### Modified File: `src/routes/products.ts`

Replace the entire file. The route handlers become thin HTTP adapters:

```typescript
import { Router } from "express";
import { listProducts, getProduct, adjustStock } from "../services/productService.js";
import { ServiceError } from "../errors.js";

const router = Router();

// GET /products
router.get("/products", (req, res) => {
  const { category, minPrice, maxPrice } = req.query;

  const filters = {
    category: typeof category === "string" ? category : undefined,
    minPrice:
      typeof minPrice === "string" && !isNaN(parseFloat(minPrice))
        ? parseFloat(minPrice)
        : undefined,
    maxPrice:
      typeof maxPrice === "string" && !isNaN(parseFloat(maxPrice))
        ? parseFloat(maxPrice)
        : undefined,
  };

  const result = listProducts(filters);
  res.json(result);
});

// GET /products/:id
router.get("/products/:id", (req, res) => {
  try {
    const id = parseInt(req.params.id, 10);
    const product = getProduct(id);
    res.json(product);
  } catch (err) {
    if (err instanceof ServiceError) {
      res.status(err.statusCode).json({ error: err.message });
      return;
    }
    throw err;
  }
});

// PATCH /products/:id/stock
router.patch("/products/:id/stock", (req, res) => {
  try {
    const id = parseInt(req.params.id, 10);
    const { adjustment } = req.body as { adjustment: number };
    const product = adjustStock(id, adjustment);
    res.json(product);
  } catch (err) {
    if (err instanceof ServiceError) {
      res.status(err.statusCode).json({ error: err.message });
      return;
    }
    throw err;
  }
});

export { router as productRouter };
```

Key points about what stays in the route handler vs. what moves:
- **Stays in route**: Parsing `req.query` strings into typed values, parsing `req.params.id`, extracting `req.body`, calling `res.json()` / `res.status()`.
- **Moves to service**: All filtering logic, computation of summary/computed fields, validation, data mutation.
- The `listProducts` call does not need try/catch because it never throws (filtering is not a failable operation).
- The `GET /products` handler does the `typeof === "string"` and `parseFloat` / `isNaN` checks because that is HTTP query-string parsing, not business logic.

---

### Modified File: `src/routes/orders.ts`

Replace the entire file:

```typescript
