├── app.ts              # UNCHANGED
├── types.ts            # MODIFIED (new interfaces appended)
├── data.ts             # UNCHANGED
├── errors.ts           # NEW
├── services/
│   ├── productService.ts  # NEW (3 exported functions)
│   └── orderService.ts    # NEW (4 exported functions)
└── routes/
    ├── products.ts     # MODIFIED (thin handlers, delegates to service)
    └── orders.ts       # MODIFIED (thin handlers, delegates to service)
tests/
├── products.test.ts    # UNCHANGED
└── orders.test.ts      # UNCHANGED
```

