  summary: OrderSummary;
}

export interface EnrichedOrderItem extends OrderItem {
  productName: string;
}

export interface EnrichedOrder extends Omit<Order, "items"> {
  items: EnrichedOrderItem[];
}
```

### Step 3: Create `src/services/product-service.ts`

Three exported functions, all importing from `../data.js`, `../errors.js`, `../types.js`:

- **`listProducts(filters: ProductFilters): ProductListResult`** - filter by category/minPrice/maxPrice, compute summary (count, totalInventoryValue, averagePrice)
- **`getProduct(id: number): ProductWithComputed`** - find by ID, compute `isLowStock` and `inventoryValue`, throw `ServiceError(404)` if not found
- **`adjustStock(id: number, adjustment: number): ProductWithComputed`** - validate adjustment is a number, check `newStock >= 0`, mutate `product.stock`, return with computed fields. Throws `ServiceError(404)` or `ServiceError(400)`.

